mapper.select:
SELECT b.id, b.course_id, c.course_name, u.username AS coach_name, b.session_id, s.session_date, s.day_of_week, s.start_time, s.end_time, b.booking_time, b.status FROM fitness_booking b LEFT JOIN fitness_course_session s ON b.session_id = s.id LEFT JOIN fitness_course c ON b.course_id = c.id LEFT JOIN sys_user u ON c.coach_id = u.id WHERE b.deleted = false
AND b.user_id = #{userId}
AND b.course_id = #{courseId}
AND b.status = #{status}
ORDER BY s.session_date DESC, s.start_time DESC

