#{id}
AND status = 1 AND deleted = false

UPDATE fitness_booking SET status = 2, cancel_reason = #{cancelReason}, update_time = CURRENT_TIMESTAMP WHERE session_id IN
#{id}
AND status = 1 AND deleted = false
